import React from "react";

function Form({ data, setData }) {
  const handleChange = (e) => {
    setData({
      ...data,
      [e.target.name]: e.target.value
    });
  };

  return (
    <div style={{ width: "50%" }}>
      <h2>Form</h2>

      {/* Basic */}
      <input name="name" placeholder="Name" value={data.name} onChange={handleChange} />
      <br /><br />
      <input name="email" placeholder="Email" value={data.email} onChange={handleChange} />
      <br /><br />
      <input name="phone" placeholder="Phone" value={data.phone} onChange={handleChange} />
      <br /><br />
      <textarea name="skills" placeholder="Skills" value={data.skills} onChange={handleChange} />

      {/* Education */}
      <h3>Education</h3>
      {data.education.map((edu, i) => (
        <div key={i}>
          <input placeholder="College" value={edu.college}
            onChange={(e) => {
              const arr = [...data.education];
              arr[i].college = e.target.value;
              setData({ ...data, education: arr });
            }}
          />
          <input placeholder="Degree" value={edu.degree}
            onChange={(e) => {
              const arr = [...data.education];
              arr[i].degree = e.target.value;
              setData({ ...data, education: arr });
            }}
          />
          <input placeholder="Year" value={edu.year}
            onChange={(e) => {
              const arr = [...data.education];
              arr[i].year = e.target.value;
              setData({ ...data, education: arr });
            }}
          />
          <button onClick={() => {
            const arr = data.education.filter((_, idx) => idx !== i);
            setData({ ...data, education: arr });
          }}>Remove</button>
          <br /><br />
        </div>
      ))}
      <button onClick={() =>
        setData({
          ...data,
          education: [...data.education, { college: "", degree: "", year: "" }]
        })
      }>Add Education</button>

      {/* Experience */}
      <h3>Experience</h3>
      {data.experience.map((exp, i) => (
        <div key={i}>
          <input placeholder="Company" value={exp.company}
            onChange={(e) => {
              const arr = [...data.experience];
              arr[i].company = e.target.value;
              setData({ ...data, experience: arr });
            }}
          />
          <input placeholder="Role" value={exp.role}
            onChange={(e) => {
              const arr = [...data.experience];
              arr[i].role = e.target.value;
              setData({ ...data, experience: arr });
            }}
          />
          <input placeholder="Year" value={exp.year}
            onChange={(e) => {
              const arr = [...data.experience];
              arr[i].year = e.target.value;
              setData({ ...data, experience: arr });
            }}
          />
          <button onClick={() => {
            const arr = data.experience.filter((_, idx) => idx !== i);
            setData({ ...data, experience: arr });
          }}>Remove</button>
          <br /><br />
        </div>
      ))}
      <button onClick={() =>
        setData({
          ...data,
          experience: [...data.experience, { company: "", role: "", year: "" }]
        })
      }>Add Experience</button>

      {/* Projects (🔥 for fresher) */}
      <h3>Projects</h3>
      {data.projects.map((proj, i) => (
        <div key={i}>
          <input placeholder="Project Title" value={proj.title}
            onChange={(e) => {
              const arr = [...data.projects];
              arr[i].title = e.target.value;
              setData({ ...data, projects: arr });
            }}
          />
          <input placeholder="Tech Stack" value={proj.tech}
            onChange={(e) => {
              const arr = [...data.projects];
              arr[i].tech = e.target.value;
              setData({ ...data, projects: arr });
            }}
          />
          <textarea placeholder="Description" value={proj.description}
            onChange={(e) => {
              const arr = [...data.projects];
              arr[i].description = e.target.value;
              setData({ ...data, projects: arr });
            }}
          />
          <button onClick={() => {
            const arr = data.projects.filter((_, idx) => idx !== i);
            setData({ ...data, projects: arr });
          }}>Remove</button>
          <br /><br />
        </div>
      ))}
      <button onClick={() =>
        setData({
          ...data,
          projects: [...data.projects, { title: "", tech: "", description: "" }]
        })
      }>Add Project</button>

    </div>
  );
}

export default Form;
